import React from 'react'
import Link from 'gatsby-link'

const CareerPage = () => (
    <div>
    <h1>My Career</h1>
      <p>I am currently working as a Cloud Software Engineer at Appian Incorporated in Reston Virginia.</p>
        <p>Before that I worked as a Software Engineering Intern at MicroStrategy Incorporated</p>
      <p> I completed my Bachelor's in Science at the University of Virginia, graduating with a double major in Computer Science and Financial Economics </p>
    </div>
)


export default CareerPage



